pub struct rbtdre_Section {
    pub name: &'static str,
    pub cases: &'static [rbtdre_Case],
}

/// A complete fixture definition — name, disposition, optional setup/teardown
/// hooks, and section array. All fixture-level metadata in one place; replaces
/// the prior side-channel matchers (sections_for_fixture, fixture_disposition,
/// needs_charge, needs_readiness_delay) keyed off the fixture name string.
///
/// `setup` runs before any cases. Failure aborts the fixture; cases do not run;
/// `teardown` still runs (finally-shaped) for any partial-state cleanup.
///
/// `teardown` runs unconditionally after cases regardless of case verdicts or
/// setup outcome. Errors are surfaced as warnings — teardown is best-effort.

/// Setup hook for crucible fixtures: charge → CrucibleActive assertion →
/// readiness delay (for service-bearing nameplates). Reads ctx from thread-
/// local. Returns Err on any step failure; engine surfaces this as a fixture
/// failure and runs teardown anyway.
///
/// Readiness-delay handling currently consults a hardcoded service-fixture
/// set; pace ₢BBAAt migrates the delay to a per-nameplate fact
/// (`RBRN_BOTTLE_READINESS_DELAY_SEC`) read by the charge tabtarget itself,
/// at which point this function loses the wait entirely.
pub fn rbtdrc_charge_crucible() -> Result<(), String> {
    RBTDRC_CTX.with(|c| {
        let mut opt = c.borrow_mut();
        let ctx = opt
            .as_mut()
            .ok_or_else(|| "rbtdrc: no invocation context for charge".to_string())?;
        zrbtdrc_charge_impl(ctx)
    })
}

